;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

if(! loading) events.push2(5);

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Food Storage"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

; ここからはボムが出るようにする
@delevent
@jump storage="main04.scn" target=*labyrinth_4

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] party.lastIsMove

@fg c=priest_purple_nude left=450
[texton]
[name n="Captive Girl" f=priest_purple_02]「Adventurer, do you want to be healed?」[k]
[textoff]
@question title="Would you like to be healed?"
[if exp='tf.result']
	@call storage="anime.ks" target=*fountain_star
	@eval exp='game.party.recovery()'
	@notice text="The party regained HP and magic!"
	@eval exp='game.hotelView.checkLevelUp()'
	[waittrig name="finishLevelUpInEvent"]
[endif]
@clf

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] party.lastIsMove

@fg c=priest_green_nude left=450
[texton]
[name n="Captive Girl" f=priest_green_02]「...Before I was captured, I was a nun in the village. Adventurer, is there anything I can help you with?
 」[k]
[textoff]
@question title="Would you like the Sister's assistance?"
@clf
@shop name=巡礼シスター cond='tf.result'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] true

@callbattle gameover=true
@delevent
@eval exp='game.inEvent = false'
@eval exp='game.treasureBox.drops = [%[itemData: o.ボム], %[itemData: o.ボム]]'
@eval exp='game.appearTreasureBox()'
@eval exp='f.saveEnabled = true'
[s]
;-------------------------------------------------------------------------------
*event_6
;[exp] WAY == "e"

@delevent
[if exp='game.map.pos[8][0].e.type == "space"']
	[eventoff]
[endif]

[texton]
[if exp='game.isFreeMode']
	[リーダー f=06]「...?」[k]
[else]
	[テオ f=06]「Hmm...?」[k]
[endif]
If you look closely, there seems to be a crack in the wall.[k]
...Perhaps, with sufficient force, the wall can be broken.[k]
[textoff]

[eventoff]
;-------------------------------------------------------------------------------
